 199→        resp.language = Some(FRONTEND_LANGUAGE.to_string());
 200→        resp.capabilities = Some(vec![
 201→            "analyze".to_string(),
 202→            "execute".to_string(),
 203→            "generate".to_string(),
 204→            "instrument".to_string(),
 205→        ]);
