 386→    fn handle_setup(&self, mut resp: Response, req: &Request) -> Response {
 387→        let file_path = match &req.file {
 388→            Some(f) => f,
 389→            None => {
 390→                resp.status = "error".to_string();
 391→                resp.code = Some("invalid_request".to_string());
 392→                resp.message = Some("setup command requires a file path".to_string());
 393→                return resp;
 394→            }
 395→        };
 396→        let level = match &req.level {
 397→            Some(l) => *l,
 398→            None => {
 399→                resp.status = "error".to_string();
 400→                resp.code = Some("invalid_request".to_string());
 401→                resp.message = Some("setup command requires a level".to_string());
 402→                return resp;
 403→            }
 404→        };
 405→        let scope = match &req.scope {
 406→            Some(s) => s.as_str(),
 407→            None => {
 408→                resp.status = "error".to_string();
 409→                resp.code = Some("invalid_request".to_string());
 410→                resp.message = Some("setup command requires a scope".to_string());
 411→                return resp;
 412→            }
 413→        };
 414→
 415→        let path = std::path::Path::new(file_path);
 416→        match crate::setup::run_setup(path, level, scope, req.parent_context.as_ref()) {
 417→            Ok(result) => {
 418→                resp.status = "setup".to_string();
 419→                resp.setup_context = Some(result.context);
 420→                resp
 421→            }
 422→            Err(crate::setup::SetupError::FileNotFound(_)) => {
 423→                resp.status = "error".to_string();
 424→                resp.code = Some("file_not_found".to_string());
 425→                resp.message = Some(format!("setup file not found: {file_path}"));
 426→                resp
 427→            }
 428→            Err(crate::setup::SetupError::CompilationFailed(msg)) => {
 429→                resp.status = "error".to_string();
 430→                resp.code = Some("compilation_error".to_string());
 431→                resp.message = Some(msg);
 432→                resp
 433→            }
 434→            Err(e) => {
 435→                resp.status = "error".to_string();
 436→                resp.code = Some("internal_error".to_string());
 437→                resp.message = Some(e.to_string());
 438→                resp
 439→            }
 440→        }
 441→    }
