 443→    fn handle_teardown(&self, mut resp: Response, req: &Request) -> Response {
 444→        let level = match &req.level {
 445→            Some(l) => *l,
 446→            None => {
 447→                resp.status = "error".to_string();
 448→                resp.code = Some("invalid_request".to_string());
 449→                resp.message = Some("teardown command requires a level".to_string());
 450→                return resp;
 451→            }
 452→        };
 453→        let scope = match &req.scope {
 454→            Some(s) => s.as_str(),
 455→            None => {
 456→                resp.status = "error".to_string();
 457→                resp.code = Some("invalid_request".to_string());
 458→                resp.message = Some("teardown command requires a scope".to_string());
 459→                return resp;
 460→            }
 461→        };
 462→
 463→        match crate::setup::run_teardown(level, scope) {
 464→            Ok(()) => {
 465→                resp.status = "teardown_ack".to_string();
 466→                resp
 467→            }
 468→            Err(e) => {
 469→                resp.status = "error".to_string();
 470→                resp.code = Some("internal_error".to_string());
 471→                resp.message = Some(e.to_string());
 472→                resp
 473→            }
 474→        }
 475→    }
